            put( "ask", CryptocomCore.this.safeNumber(ticker, "k") );
            put( "askVolume", CryptocomCore.this.safeNumber(ticker, "ks") );
            put( "vwap", null );
            put( "open", null );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", CryptocomCore.this.safeString(ticker, "c") );
            put( "average", null );
